#!/usr/bin/env node
// SPDX-FileCopyrightText: 2025-2026 Evgenij Cjura and project contributors
// SPDX-License-Identifier: AGPL-3.0-or-later
// Scan docs/LUA_API.md for `### ... \`zhac.NAME(args) → type\`` headers
// and emit src/editor/zhac-completions.js with one entry per function.
// Runs as the `prebuild` npm script so the generated file always tracks
// the current docs.
//
// Source of truth: docs/LUA_API.md. Do not hand-edit the generated file.

import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const here    = dirname(fileURLToPath(import.meta.url));
const outPath = resolve(here, "../src/editor/zhac-completions.js");

// LUA_API.md lives in different places depending on checkout layout:
//   - monorepo:                           <root>/docs/LUA_API.md
//   - split (www-spa sibling):            ../zhac-docs/LUA_API.md
//   - split (nested under net-core):      ../../zhac-docs/LUA_API.md
//   - split (platform → net-core → www):  ../../../zhac-docs/LUA_API.md
// ZHAC_LUA_DOC env var overrides everything.
const candidates = [
    process.env.ZHAC_LUA_DOC,
    resolve(here, "../../docs/LUA_API.md"),
    resolve(here, "../../zhac-docs/LUA_API.md"),
    resolve(here, "../../../zhac-docs/LUA_API.md"),
    resolve(here, "../../../../zhac-docs/LUA_API.md"),
].filter(Boolean);

const docPath = candidates.find(p => existsSync(p));
if (!docPath) {
    console.error("gen-zhac-completions: LUA_API.md not found. Tried:");
    for (const p of candidates) console.error("  " + p);
    console.error("Set ZHAC_LUA_DOC=/abs/path/to/LUA_API.md to override.");
    process.exit(1);
}
const raw = readFileSync(docPath, "utf8");
const lines = raw.split("\n");

const HEAD_RE = /^###\s+(?:\d+(?:\.\d+)*\s+)?`(zhac\.[^`]+)`(?:\s*—.*)?$/;
const seen = new Map();   // label -> {detail, info}

for (let i = 0; i < lines.length; i++) {
    const m = HEAD_RE.exec(lines[i].trim());
    if (!m) continue;

    const sigRaw = m[1];                              // zhac.foo(a, b) → bool
    const parenIdx = sigRaw.indexOf("(");
    const label = parenIdx > 0 ? sigRaw.slice(0, parenIdx) : sigRaw;

    // Skip "see §x.y" cross-refs — we already have the canonical entry.
    const tail = lines[i].trim();
    if (/see §/i.test(tail)) continue;

    // First non-blank paragraph after the heading = short blurb.
    let info = "";
    for (let j = i + 1; j < lines.length && j < i + 12; j++) {
        const L = lines[j].trim();
        if (!L) { if (info) break; else continue; }
        if (L.startsWith("###")) break;                // hit next heading
        if (L.startsWith("```") || L.startsWith("|"))  // skip code / tables
            { if (info) break; else continue; }
        info += (info ? " " : "") + L;
        if (info.length > 180) break;
    }
    info = info.replace(/\s+/g, " ")
               .replace(/`([^`]+)`/g, "$1")           // strip inline backticks
               .slice(0, 180);

    // Prefer the richest description if we hit the same label twice.
    const prev = seen.get(label);
    if (!prev || info.length > prev.info.length) {
        seen.set(label, { detail: sigRaw.slice(label.length), info });
    }
}

const entries = Array.from(seen, ([label, v]) => ({ label, ...v }))
                     .sort((a, b) => a.label.localeCompare(b.label));

const out = `// AUTO-GENERATED by www-spa/tools/gen-zhac-completions.js
// Source: docs/LUA_API.md. Run \`npm run gen:completions\` (or any
// \`npm run build\`, which hooks this via prebuild) to refresh.
// DO NOT HAND-EDIT — regenerate from the docs instead.

export const ZHAC_API = ${JSON.stringify(entries, null, 4)};
`;

writeFileSync(outPath, out);
console.log(`gen-zhac-completions: ${entries.length} entries → ${outPath}`);
